count=0
echo "$menus" | jq -c '.[]' | while read -r restaurant; do
  rest_id=$(echo "$restaurant" | jq -r '.rest')

  echo "$restaurant" | jq -c '.items[]' | while read -r item; do
    item_id=$(echo "$item" | jq -r '.id')
    name=$(echo "$item" | jq -r '.name')
    desc=$(echo "$item" | jq -r '.desc')
    price=$(echo "$item" | jq -r '.price')
    img=$(echo "$item" | jq -r '.img')

    aws dynamodb put-item --table-name $TABLE_NAME --region $REGION --item "{
      \"item_id\": {\"S\": \"$item_id\"},
      \"restaurant_id\": {\"S\": \"$rest_id\"},
      \"name\": {\"S\": \"$name\"},
      \"description\": {\"S\": \"$desc\"},
      \"price\": {\"N\": \"$price\"},
      \"image_url\": {\"S\": \"$img\"},
      \"is_available\": {\"BOOL\": true}
    }" > /dev/null 2>&1

  done
  echo "✓ Added menu for restaurant $rest_id"
done

echo ""
echo "Successfully seeded menu items for all 20 restaurants!"
echo ""
echo "Verifying data..."
aws dynamodb scan --table-name $TABLE_NAME --region $REGION --select COUNT
